BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?comment ?body ?annotatedElement ?elemName WHERE {
  ?comment rdf:type vocab:comment .
  ?comment vocab:Comment_body ?body .
  OPTIONAL { ?comment vocab:Comment_annotatedElement ?annotatedElement .
             ?annotatedElement vocab:NamedElement_name ?elemName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?model ?name ?type WHERE {
  ?model rdf:type ?type .
  FILTER(CONTAINS(STR(?type), "Model") || CONTAINS(STR(?type), "model"))
  OPTIONAL { ?model vocab:NamedElement_name ?name }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?name ?comment ?body WHERE {
  ?pkg rdf:type vocab:package .
  ?pkg vocab:NamedElement_name "TMT" .
  OPTIONAL {
    ?comment rdf:type vocab:comment .
    ?comment vocab:Comment_annotatedElement ?pkg .
    ?comment vocab:Comment_body ?body .
  }
  OPTIONAL { ?pkg vocab:NamedElement_name ?name }
}
LIMIT 25
